"""Sprint69-2B Runtime Health統合ファイルを全文置換する。"""
from __future__ import annotations
import base64
from pathlib import Path
FILES = {
    Path('app/runtime/session_models.py'): '',
    Path('app/runtime/session_service.py'): '',
    Path('app/runtime/runtime_health_monitor_reader.py'): '',
    Path('app/runtime/session_report.py'): '',
    Path('app/dashboard/dashboard_models.py'): '',
    Path('app/dashboard/dashboard_service.py'): '',
    Path('app/dashboard/dashboard_json.py'): '',
}
for path, data in FILES.items():
    text = base64.b64decode(data).decode('utf-8')
    compile(text, str(path), 'exec')
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding='utf-8', newline='\n')
    print(f'updated: {path}')
checks = {
 'session timestamps': 'last_heartbeat_at' in Path('app/runtime/session_models.py').read_text(encoding='utf-8'),
 'health reader': Path('app/runtime/runtime_health_monitor_reader.py').exists(),
 'dashboard health': 'runtime_health' in Path('app/dashboard/dashboard_models.py').read_text(encoding='utf-8'),
 'dashboard json': 'runtime_health_monitor_report_to_dict' in Path('app/dashboard/dashboard_json.py').read_text(encoding='utf-8'),
}
failed = [k for k, v in checks.items() if not v]
if failed:
    raise RuntimeError(f'置換確認に失敗しました: {failed}')
print('Sprint69-2B files were replaced successfully.')
for key in checks:
    print(f'  OK: {key}')
